const REFRESH_INTERVAL = 30_000;

// ── Format Helpers ─────────────────────────────────────────────────────────────
function fmt(v, dec = 0) {
  if (v == null || isNaN(v)) return '-';
  return Number(v).toLocaleString(undefined, { minimumFractionDigits: dec, maximumFractionDigits: dec });
}
function fmtPct(v, dec = 1) {
  if (v == null || isNaN(v)) return '-';
  return `${(Number(v) * 100).toFixed(dec)}%`;
}
function fmtBps(v, dec = 1) {
  if (v == null || isNaN(v)) return '-';
  return `${Number(v).toFixed(dec)} bps`;
}
function fmtMs(v, dec = 0) {
  if (v == null || isNaN(v)) return '-';
  return `${Number(v).toFixed(dec)}ms`;
}
function fmtUsd(v, dec = 2) {
  if (v == null || isNaN(v)) return '-';
  return `$${Number(v).toFixed(dec)}`;
}
function fmtTime(ts) {
  if (!ts) return '-';
  const d = new Date(typeof ts === 'number' && ts < 1e12 ? ts * 1000 : ts);
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

// ── Color helpers ──────────────────────────────────────────────────────────────
function qualityColor(v, thresholds) {
  if (v == null) return RAW.textSecondary;
  if (v >= thresholds.good) return RAW.green;
  if (v >= thresholds.mid) return RAW.amber;
  return RAW.red;
}
function qualityColorInverse(v, thresholds) {
  if (v == null) return RAW.textSecondary;
  if (v <= thresholds.good) return RAW.green;
  if (v <= thresholds.mid) return RAW.amber;
  return RAW.red;
}

