// ── Fill Rate Gauge (SVG) ──────────────────────────────────────────────────────
function FillRateGauge({ rate, total, filled }) {
  const pct = rate != null ? Math.min(rate * 100, 100) : 0;
  const radius = 70;
  const stroke = 12;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (pct / 100) * circumference;
  const color = pct >= 95 ? RAW.green : pct >= 80 ? RAW.amber : RAW.red;

  return (
    <div className={s.gaugeWrap}>
      <svg width="180" height="180" viewBox="0 0 180 180">
        {/* Track */}
        <circle cx="90" cy="90" r={radius} fill="none" stroke={RAW.surface2} strokeWidth={stroke} />
        {/* Fill arc */}
        <circle
          cx="90" cy="90" r={radius} fill="none"
          stroke={color} strokeWidth={stroke}
          strokeLinecap="round"
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          transform="rotate(-90 90 90)"
          style={{ transition: 'stroke-dashoffset 0.6s ease' }}
        />
        {/* Center text */}
        <text x="90" y="82" textAnchor="middle" fill={color} fontSize="32" fontWeight="700" fontFamily="'JetBrains Mono', monospace">
          {pct.toFixed(1)}%
        </text>
        <text x="90" y="105" textAnchor="middle" fill={RAW.textSecondary} fontSize="12">
          Fill Rate
        </text>
      </svg>
      <div className={s.gaugeStats}>
        <span>{filled ?? '-'} filled</span>
        <span className={s.gaugeSep}>/</span>
        <span>{total ?? '-'} total</span>
      </div>
    </div>
  );
}

// ── Slippage Histogram (SVG) ───────────────────────────────────────────────────
function SlippageHistogram({ buckets }) {
  if (!buckets || buckets.length === 0) return <div className={s.noData}>No slippage data</div>;
  const maxCount = Math.max(...buckets.map(b => b.count), 1);
  const barWidth = 36;
  const gap = 8;
  const chartH = 160;
  const chartW = buckets.length * (barWidth + gap);

  return (
    <div className={s.svgChartWrap}>
      <svg width={chartW} height={chartH + 40} viewBox={`0 0 ${chartW} ${chartH + 40}`}>
        {buckets.map((b, i) => {
          const barH = maxCount > 0 ? (b.count / maxCount) * chartH : 0;
          const x = i * (barWidth + gap);
          const y = chartH - barH;
          const barColor = b.midBps != null
            ? (b.midBps <= 2 ? RAW.green : b.midBps <= 5 ? RAW.blue : b.midBps <= 10 ? RAW.amber : RAW.red)
            : RAW.blue;
          return (
            <g key={b.label}>
              <rect x={x} y={y} width={barWidth} height={barH} rx={4} fill={barColor} opacity={0.85} />
              <text x={x + barWidth / 2} y={y - 6} textAnchor="middle" fill={RAW.textSecondary} fontSize="11" fontFamily="'JetBrains Mono', monospace">
                {b.count}
              </text>
              <text x={x + barWidth / 2} y={chartH + 16} textAnchor="middle" fill={RAW.textSecondary} fontSize="10">
                {b.label}
              </text>
            </g>
          );
        })}
      </svg>
      <div className={s.chartLabel}>Slippage (bps)</div>
    </div>
  );
}

// ── Latency Timeline (SVG) ────────────────────────────────────────────────────
function LatencyTimeline({ points }) {
  if (!points || points.length < 2) return <div className={s.noData}>No latency data</div>;
  const chartW = 600;
  const chartH = 160;
  const pad = { top: 10, right: 20, bottom: 30, left: 50 };
  const w = chartW - pad.left - pad.right;
  const h = chartH - pad.top - pad.bottom;
  const maxVal = Math.max(...points.map(p => p.value), 1);
  const minVal = 0;
  const range = maxVal - minVal || 1;

  const pathD = points.map((p, i) => {
    const x = pad.left + (i / (points.length - 1)) * w;
    const y = pad.top + h - ((p.value - minVal) / range) * h;
    return `${i === 0 ? 'M' : 'L'} ${x.toFixed(1)} ${y.toFixed(1)}`;
  }).join(' ');

  // Area fill
  const firstX = pad.left;
  const lastX = pad.left + w;
  const bottomY = pad.top + h;
  const areaD = `${pathD} L ${lastX.toFixed(1)} ${bottomY} L ${firstX} ${bottomY} Z`;

  // Y-axis ticks
  const yTicks = [0, 0.25, 0.5, 0.75, 1].map(f => ({
    val: (minVal + f * range).toFixed(0),
    y: pad.top + h - f * h,
  }));

  // X-axis labels (show a few)
  const step = Math.max(1, Math.floor(points.length / 6));
  const xLabels = points.filter((_, i) => i % step === 0 || i === points.length - 1);

  return (
    <div className={s.svgChartWrap}>
      <svg width={chartW} height={chartH} viewBox={`0 0 ${chartW} ${chartH}`}>
        <defs>
          <linearGradient id="latGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={RAW.blue} stopOpacity="0.3" />
            <stop offset="100%" stopColor={RAW.blue} stopOpacity="0.02" />
          </linearGradient>
        </defs>
        {/* Grid lines */}
        {yTicks.map(t => (
          <g key={t.val}>
            <line x1={pad.left} y1={t.y} x2={pad.left + w} y2={t.y} stroke={RAW.border} strokeWidth="0.5" />
            <text x={pad.left - 6} y={t.y + 4} textAnchor="end" fill={RAW.textSecondary} fontSize="10" fontFamily="'JetBrains Mono', monospace">
              {t.val}
            </text>
          </g>
        ))}
        {/* Area */}
        <path d={areaD} fill="url(#latGrad)" />
        {/* Line */}
        <path d={pathD} fill="none" stroke={RAW.blue} strokeWidth="2" strokeLinejoin="round" />
        {/* Dots */}
        {points.map((p, i) => {
          const x = pad.left + (i / (points.length - 1)) * w;
          const y = pad.top + h - ((p.value - minVal) / range) * h;
          return <circle key={i} cx={x} cy={y} r={2.5} fill={RAW.blue} />;
        })}
        {/* X labels */}
        {xLabels.map((p, i) => {
          const idx = points.indexOf(p);
          const x = pad.left + (idx / (points.length - 1)) * w;
          return (
            <text key={i} x={x} y={chartH - 4} textAnchor="middle" fill={RAW.textSecondary} fontSize="9">
              {p.label}
            </text>
          );
        })}
        {/* Y label */}
        <text x={8} y={pad.top + h / 2} textAnchor="middle" fill={RAW.textSecondary} fontSize="10" transform={`rotate(-90, 8, ${pad.top + h / 2})`}>
          ms
        </text>
      </svg>
    </div>
  );
}

// ── Market Impact Breakdown (SVG donut) ────────────────────────────────────────
function MarketImpactDonut({ segments }) {
  if (!segments || segments.length === 0) return <div className={s.noData}>No impact data</div>;
  const total = segments.reduce((a, seg) => a + seg.value, 0) || 1;
  const radius = 60;
  const stroke = 20;
  const circumference = 2 * Math.PI * radius;
  const colors = [RAW.blue, RAW.green, RAW.amber, RAW.red, RAW.purple, RAW.cyan];
  let accum = 0;

  return (
    <div className={s.donutWrap}>
      <svg width="160" height="160" viewBox="0 0 160 160">
        {segments.map((seg, i) => {
          const pct = seg.value / total;
          const dashLen = pct * circumference;
          const dashOff = -(accum / total) * circumference;
          accum += seg.value;
          return (
            <circle
              key={seg.label}
              cx="80" cy="80" r={radius} fill="none"
              stroke={colors[i % colors.length]}
              strokeWidth={stroke}
              strokeDasharray={`${dashLen} ${circumference - dashLen}`}
              strokeDashoffset={dashOff}
              transform="rotate(-90 80 80)"
              opacity={0.85}
            />
          );
        })}
        <text x="80" y="78" textAnchor="middle" fill={RAW.textPrimary} fontSize="18" fontWeight="700" fontFamily="'JetBrains Mono', monospace">
          {fmtBps(total)}
        </text>
        <text x="80" y="96" textAnchor="middle" fill={RAW.textSecondary} fontSize="10">
          total impact
        </text>
      </svg>
      <div className={s.donutLegend}>
        {segments.map((seg, i) => (
          <div key={seg.label} className={s.donutLegendItem}>
            <span className={s.donutDot} style={{ backgroundColor: colors[i % colors.length] }} />
            <span className={s.donutLegendLabel}>{seg.label}</span>
            <span className={s.donutLegendVal}>{fmtBps(seg.value)}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

