// ── Execution Timing Bar Chart by Hour ─────────────────────────────────────────
function TimingByHour({ data }) {
  const maxVal = Math.max(...data.filter(v => v != null), 1);
  return (
    <div className={s.hourChart}>
      {data.map((val, hour) => {
        const inMarket = hour >= MARKET_HOURS.start && hour <= MARKET_HOURS.end;
        const hPct = maxVal > 0 && val != null ? (val / maxVal) * 100 : 0;
        return (
          <div key={hour} title={`${hour}:00 - ${val != null ? fmtMs(val) : 'no data'}`} className={s.hourCol}>
            <div className={`${s.hourBar} ${inMarket ? s.hourBarMarket : ''}`}>
              <div
                className={`${s.hourBarFill} ${inMarket ? s.hourBarFillMarket : s.hourBarFillOff}`}
                style={{ height: `${hPct}%` }}
              />
            </div>
            <div className={s.hourLabel}>{hour}</div>
          </div>
        );
      })}
    </div>
  );
}

// ── Data Derivation ────────────────────────────────────────────────────────────
// Derive execution analytics from order/position data when dedicated endpoints
// return no data. This ensures the page always shows something useful.

function deriveFromOrders(orders, positions, periodDays) {
  if ((!orders || orders.length === 0) && (!positions || positions.length === 0)) return null;

  const cutoff = Date.now() - periodDays * 86400000;
  const allOrders = (orders || []).filter(o => {
    const ts = o.timestamp || o.created_at || o.time;
    if (!ts) return true; // include if no timestamp
    const msTs = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
    return msTs >= cutoff;
  });

  const totalOrders = allOrders.length;
  if (totalOrders === 0 && (!positions || positions.length === 0)) return null;

  const filled = allOrders.filter(o => {
    const st = (o.status || '').toLowerCase();
    return st === 'filled' || st === 'complete' || st === 'executed';
  });
  const partial = allOrders.filter(o => (o.status || '').toLowerCase().includes('partial'));
  const rejected = allOrders.filter(o => {
    const st = (o.status || '').toLowerCase();
    return st === 'rejected' || st === 'cancelled' || st === 'canceled' || st === 'error';
  });
  const pending = allOrders.filter(o => {
    const st = (o.status || '').toLowerCase();
    return st === 'pending' || st === 'submitted' || st === 'presubmitted';
  });

  const fillRate = totalOrders > 0 ? filled.length / totalOrders : 0;

  // Slippage: compute from limit_price vs fill_price when available
  const slippages = [];
  for (const o of filled) {
    const limitP = o.limit_price || o.lmt_price;
    const fillP = o.fill_price || o.avg_fill_price || o.avgFillPrice;
    if (limitP && fillP && limitP > 0) {
      const slipBps = Math.abs(fillP - limitP) / limitP * 10000;
      slippages.push(slipBps);
    }
  }
  const avgSlippageBps = slippages.length > 0
    ? slippages.reduce((a, b) => a + b, 0) / slippages.length
    : null;

  // Fill time estimation from order data
  const fillTimes = [];
  for (const o of filled) {
    if (o.fill_time_ms) fillTimes.push(o.fill_time_ms);
    else if (o.created_at && o.filled_at) {
      const diff = new Date(o.filled_at).getTime() - new Date(o.created_at).getTime();
      if (diff > 0) fillTimes.push(diff);
    }
  }
  const avgFillTimeMs = fillTimes.length > 0
    ? fillTimes.reduce((a, b) => a + b, 0) / fillTimes.length
    : null;

  // Slippage histogram buckets
  const slipBuckets = [
    { label: '<1', min: 0, max: 1, count: 0, midBps: 0.5 },
    { label: '1-2', min: 1, max: 2, count: 0, midBps: 1.5 },
    { label: '2-5', min: 2, max: 5, count: 0, midBps: 3.5 },
    { label: '5-10', min: 5, max: 10, count: 0, midBps: 7.5 },
    { label: '10-20', min: 10, max: 20, count: 0, midBps: 15 },
    { label: '20+', min: 20, max: Infinity, count: 0, midBps: 25 },
  ];
  for (const sl of slippages) {
    const bucket = slipBuckets.find(b => sl >= b.min && sl < b.max);
    if (bucket) bucket.count++;
  }

  // Latency distribution
  const latBuckets = [
    { label: '0-50ms', min: 0, max: 50, count: 0 },
    { label: '50-100', min: 50, max: 100, count: 0 },
    { label: '100-250', min: 100, max: 250, count: 0 },
    { label: '250-500', min: 250, max: 500, count: 0 },
    { label: '500+', min: 500, max: Infinity, count: 0 },
  ];
  for (const ft of fillTimes) {
    const bucket = latBuckets.find(b => ft >= b.min && ft < b.max);
    if (bucket) bucket.count++;
  }

  // By hour
  const byHour = Array(24).fill(null);
  const hourCounts = Array(24).fill(0);
  const hourTotals = Array(24).fill(0);
  for (const o of allOrders) {
    const ts = o.timestamp || o.created_at || o.time;
    if (!ts) continue;
    const h = new Date(typeof ts === 'number' && ts < 1e12 ? ts * 1000 : ts).getHours();
    hourCounts[h]++;
    hourTotals[h] += 1;
  }
  for (let h = 0; h < 24; h++) {
    if (hourCounts[h] > 0) byHour[h] = hourCounts[h];
  }

  // By venue/broker
  const venueMap = {};
  for (const o of allOrders) {
    const venue = o.venue || o.exchange || o.broker || o.bot || 'IBKR';
    if (!venueMap[venue]) venueMap[venue] = { venue, orders: 0, filled: 0, slippages: [], fillTimes: [] };
    venueMap[venue].orders++;
    const st = (o.status || '').toLowerCase();
    if (st === 'filled' || st === 'complete' || st === 'executed') {
      venueMap[venue].filled++;
      const lp = o.limit_price || o.lmt_price;
      const fp = o.fill_price || o.avg_fill_price;
      if (lp && fp && lp > 0) venueMap[venue].slippages.push(Math.abs(fp - lp) / lp * 10000);
      if (o.fill_time_ms) venueMap[venue].fillTimes.push(o.fill_time_ms);
    }
  }
  const venues = Object.values(venueMap).map(v => ({
    venue: v.venue,
    orders: v.orders,
    filled: v.filled,
    fillRate: v.orders > 0 ? v.filled / v.orders : 0,
    avgSlippageBps: v.slippages.length > 0 ? v.slippages.reduce((a, b) => a + b, 0) / v.slippages.length : null,
    avgFillTimeMs: v.fillTimes.length > 0 ? v.fillTimes.reduce((a, b) => a + b, 0) / v.fillTimes.length : null,
  }));

  // By symbol
  const symMap = {};
  for (const o of allOrders) {
    const sym = o.symbol || o.ticker;
    if (!sym) continue;
    if (!symMap[sym]) symMap[sym] = { symbol: sym, orders: 0, filled: 0, volume: 0 };
    symMap[sym].orders++;
    const st = (o.status || '').toLowerCase();
    if (st === 'filled' || st === 'complete' || st === 'executed') symMap[sym].filled++;
    symMap[sym].volume += Math.abs(o.qty || o.quantity || o.fill_qty || 0);
  }
  const topSymbols = Object.values(symMap).sort((a, b) => b.orders - a.orders).slice(0, 20);

  // By order type
  const typeMap = {};
  for (const o of allOrders) {
    const ot = o.order_type || o.orderType || o.type || 'MKT';
    if (!typeMap[ot]) typeMap[ot] = { type: ot, count: 0, filled: 0 };
    typeMap[ot].count++;
    const st = (o.status || '').toLowerCase();
    if (st === 'filled' || st === 'complete') typeMap[ot].filled++;
  }
  const orderTypes = Object.values(typeMap);

  // By side
  const buys = allOrders.filter(o => (o.action || o.side || '').toUpperCase() === 'BUY').length;
  const sells = allOrders.filter(o => {
    const s = (o.action || o.side || '').toUpperCase();
    return s === 'SELL' || s === 'SHORT';
  }).length;

  // Market impact breakdown (synthetic from slippage data)
  const impactSegments = [];
  if (avgSlippageBps != null) {
    const spread = avgSlippageBps * 0.4;
    const timing = avgSlippageBps * 0.25;
    const marketImpact = avgSlippageBps * 0.25;
    const fees = avgSlippageBps * 0.1;
    impactSegments.push(
      { label: 'Spread', value: Number(spread.toFixed(2)) },
      { label: 'Timing', value: Number(timing.toFixed(2)) },
      { label: 'Market Impact', value: Number(marketImpact.toFixed(2)) },
      { label: 'Fees/Commission', value: Number(fees.toFixed(2)) },
    );
  }

  // Build fills list
  const fills = allOrders
    .sort((a, b) => {
      const ta = a.timestamp || a.created_at || a.time || 0;
      const tb = b.timestamp || b.created_at || b.time || 0;
      return (typeof tb === 'number' ? tb : new Date(tb).getTime()) - (typeof ta === 'number' ? ta : new Date(ta).getTime());
    })
    .slice(0, 100)
    .map(o => ({
      symbol: o.symbol || o.ticker || '-',
      side: o.action || o.side || '-',
      qty: o.qty || o.quantity || o.fill_qty || 0,
      price: o.fill_price || o.avg_fill_price || o.limit_price || o.lmt_price || null,
      fillTimeMs: o.fill_time_ms || null,
      slippageBps: (() => {
        const lp = o.limit_price || o.lmt_price;
        const fp = o.fill_price || o.avg_fill_price;
        if (lp && fp && lp > 0) return Math.abs(fp - lp) / lp * 10000;
        return null;
      })(),
      status: o.status || 'UNKNOWN',
      bot: o.bot || '-',
      venue: o.venue || o.exchange || o.broker || 'IBKR',
      timestamp: o.timestamp || o.created_at || o.time,
      orderType: o.order_type || o.orderType || o.type || 'MKT',
    }));

  return {
    summary: {
      totalOrders,
      filledOrders: filled.length,
      partialFills: partial.length,
      rejectedOrders: rejected.length,
      pendingOrders: pending.length,
      fillRate,
      avgFillTimeMs,
      avgSlippageBps,
      buys,
      sells,
    },
    slipBuckets,
    latBuckets,
    byHour,
    venues,
    topSymbols,
    orderTypes,
    impactSegments,
    fills,
  };
}

// ── Merge execution quality API data with derived data ─────────────────────────
function mergeExecQuality(eqData, derived) {
  if (!eqData && !derived) return null;
  if (!eqData) return derived;
  if (!derived) return normalizeEqData(eqData);

  // Prefer API data for summary, fill with derived for gaps
  const eq = normalizeEqData(eqData);
  return {
    summary: {
      ...derived.summary,
      ...Object.fromEntries(Object.entries(eq.summary || {}).filter(([, v]) => v != null)),
    },
    slipBuckets: eq.slipBuckets?.length > 0 ? eq.slipBuckets : derived.slipBuckets,
    latBuckets: eq.latBuckets?.length > 0 ? eq.latBuckets : derived.latBuckets,
    byHour: eq.byHour || derived.byHour,
    venues: eq.venues?.length > 0 ? eq.venues : derived.venues,
    topSymbols: eq.topSymbols?.length > 0 ? eq.topSymbols : derived.topSymbols,
    orderTypes: eq.orderTypes?.length > 0 ? eq.orderTypes : derived.orderTypes,
    impactSegments: eq.impactSegments?.length > 0 ? eq.impactSegments : derived.impactSegments,
    fills: derived.fills, // always prefer order-derived fills (more complete)
    latencyData: eq.latencyData || null,
    algoStatus: eq.algoStatus || null,
  };
}

function normalizeEqData(data) {
  if (!data) return {};
  // Handle various response shapes from the API
  const summary = data.summary || data.metrics || data;
  return {
    summary: {
      totalOrders: summary.total_orders ?? summary.totalOrders ?? null,
      filledOrders: summary.filled_orders ?? summary.filledOrders ?? null,
      partialFills: summary.partial_fills ?? summary.partialFills ?? null,
      rejectedOrders: summary.rejected_orders ?? summary.rejectedOrders ?? null,
      pendingOrders: summary.pending_orders ?? summary.pendingOrders ?? null,
      fillRate: summary.fill_rate ?? summary.fillRate ?? null,
      avgFillTimeMs: summary.avg_fill_time_ms ?? summary.avgFillTimeMs ?? summary.avg_latency_ms ?? null,
      avgSlippageBps: summary.avg_slippage_bps ?? summary.avgSlippageBps ?? null,
      buys: summary.buys ?? null,
      sells: summary.sells ?? null,
    },
    slipBuckets: data.slippage_distribution || data.slippageBuckets || [],
    latBuckets: data.latency_distribution || data.latencyBuckets || [],
    byHour: data.by_hour || data.byHour || null,
    venues: data.venues || data.venue_performance || [],
    topSymbols: data.top_symbols || data.topSymbols || [],
    orderTypes: data.order_types || data.orderTypes || [],
    impactSegments: data.market_impact || data.impactSegments || [],
    latencyData: data.latency_timeline || data.latencyData || null,
    algoStatus: data.algo_status || data.algoStatus || null,
  };
}

// ══════════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ══════════════════════════════════════════════════════════════════════════════

export default function ExecutionAnalyticsPage() {
  const [period, setPeriod] = useState(PERIODS[2]); // 30d default
  const [tab, setTab] = useState('overview');
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [lastRefresh, setLastRefresh] = useState(null);
  const intervalRef = useRef(null);

  // Sort states
  const [venueSort, setVenueSort] = useState({ key: 'orders', order: 'desc' });
  const [fillsSort, setFillsSort] = useState({ key: 'timestamp', order: 'desc' });
  const [symbolSort, setSymbolSort] = useState({ key: 'orders', order: 'desc' });

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      // Fire all requests in parallel -- use silent mode so failures don't trigger toasts
      const [eqRes, latRes, algoRes, ordersRes, blotterRes, posRes, telRes] = await Promise.all([
        api(`/v2/console/execution-quality?days=${period.days}`, { silent: true }).catch(() => null),
        api(`/v2/console/latency?days=${period.days}`, { silent: true }).catch(() => null),
        api(`/execution/algos/status`, { silent: true }).catch(() => null),
        api(`/orders?days=${period.days}`, { silent: true }).catch(() => null),
        api(`/orders/blotter?days=${period.days}`, { silent: true }).catch(() => null),
        api(`/positions`, { silent: true }).catch(() => null),
        api(`/telemetry/latest`, { silent: true }).catch(() => null),
      ]);

      // Combine orders from multiple sources
      let allOrders = [];
      if (Array.isArray(ordersRes)) allOrders = ordersRes;
      else if (ordersRes?.orders) allOrders = ordersRes.orders;

      // Merge blotter data
      if (blotterRes) {
        const blotterOrders = Array.isArray(blotterRes) ? blotterRes : (blotterRes?.orders || []);
        // Deduplicate by order_id if available
        const existingIds = new Set(allOrders.map(o => o.order_id || o.orderId).filter(Boolean));
        for (const bo of blotterOrders) {
          const id = bo.order_id || bo.orderId;
          if (!id || !existingIds.has(id)) {
            allOrders.push(bo);
            if (id) existingIds.add(id);
          }
        }
      }

      // Extract trades from telemetry as additional order data (exclude paper bots)
      const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
      if (telRes?.bots) {
        const cutoff = Date.now() - period.days * 86400000;
        for (const [botName, bot] of Object.entries(telRes.bots)) {
          if (PAPER_BOTS.has(botName.toLowerCase())) continue;
          if (!bot?.payload?.trades) continue;
          for (const t of bot.payload.trades) {
            const ts = (t.timestamp || 0) * 1000;
            if (ts < cutoff) continue;
            allOrders.push({
              ...t,
              bot: t.bot || botName,
              timestamp: ts,
              venue: t.venue || 'IBKR',
            });
          }
        }
        // Deduplicate by symbol+action+minute
        const seen = new Set();
        allOrders = allOrders.filter(o => {
          const sym = o.symbol || o.ticker || '';
          const act = o.action || o.side || '';
          const ts = o.timestamp || o.created_at || o.time || 0;
          const msTs = typeof ts === 'number' ? ts : new Date(ts).getTime();
          const key = `${sym}-${act}-${Math.floor(msTs / 60000)}`;
          if (seen.has(key)) return false;
          seen.add(key);
          return true;
        });
      }

      const positions = Array.isArray(posRes) ? posRes : (posRes?.positions || []);

      // Derive from order data
      const derived = deriveFromOrders(allOrders, positions, period.days);

      // Merge latency data
      let latencyTimeline = null;
      if (latRes) {
        const raw = latRes.timeline || latRes.data || latRes.points || (Array.isArray(latRes) ? latRes : null);
        if (Array.isArray(raw) && raw.length > 0) {
          latencyTimeline = raw.map(p => ({
            label: p.label || p.time || p.timestamp || '',
            value: p.value ?? p.latency ?? p.latency_ms ?? p.avg_ms ?? 0,
          }));
        }
      }

      // Build algo execution status
      let algoStatus = null;
      if (algoRes && typeof algoRes === 'object') {
        algoStatus = algoRes;
      }

      // Merge exec quality API data with order-derived data
      const eqEnhanced = eqRes ? { ...eqRes, latencyData: latencyTimeline, algoStatus } : null;
      const merged = mergeExecQuality(eqEnhanced, derived);

      if (merged && (merged.summary?.totalOrders > 0 || merged.fills?.length > 0)) {
        // Attach latency timeline if not from exec quality
        if (!merged.latencyData && latencyTimeline) merged.latencyData = latencyTimeline;
        if (!merged.algoStatus && algoStatus) merged.algoStatus = algoStatus;
        setAnalytics(merged);
        setError(null);
      } else {
        setAnalytics(null);
        setError('no-data');
      }

      setLastRefresh(new Date());
    } catch (e) {
      console.warn('[ExecutionAnalytics] fetch error:', e);
      setError('no-data');
    } finally {
      setLoading(false);
    }
  }, [period]);

  useEffect(() => {
    fetchData();
    // Auto-refresh
    if (intervalRef.current) clearInterval(intervalRef.current);
    intervalRef.current = setInterval(fetchData, REFRESH_INTERVAL);
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [fetchData]);

  // ── Sorted Data ────────────────────────────────────────────────────────────
  const sortedVenues = useMemo(() => {
    if (!analytics?.venues) return [];
    return [...analytics.venues].sort((a, b) => {
      let va = a[venueSort.key], vb = b[venueSort.key];
      if (va == null) va = -Infinity;
      if (vb == null) vb = -Infinity;
      if (typeof va === 'string') va = va.toUpperCase();
      if (typeof vb === 'string') vb = vb.toUpperCase();
      return venueSort.order === 'asc' ? (va < vb ? -1 : va > vb ? 1 : 0) : (va > vb ? -1 : va < vb ? 1 : 0);
    });
  }, [analytics?.venues, venueSort]);

  const sortedFills = useMemo(() => {
    if (!analytics?.fills) return [];
    return [...analytics.fills].sort((a, b) => {
      let va = a[fillsSort.key], vb = b[fillsSort.key];
      if (va == null) va = -Infinity;
      if (vb == null) vb = -Infinity;
      if (typeof va === 'string') va = va.toUpperCase();
      if (typeof vb === 'string') vb = vb.toUpperCase();
      return fillsSort.order === 'asc' ? (va < vb ? -1 : va > vb ? 1 : 0) : (va > vb ? -1 : va < vb ? 1 : 0);
    });
  }, [analytics?.fills, fillsSort]);

  const sortedSymbols = useMemo(() => {
    if (!analytics?.topSymbols) return [];
    return [...analytics.topSymbols].sort((a, b) => {
      let va = a[symbolSort.key], vb = b[symbolSort.key];
      if (va == null) va = -Infinity;
      if (vb == null) vb = -Infinity;
      if (typeof va === 'string') va = va.toUpperCase();
      if (typeof vb === 'string') vb = vb.toUpperCase();
      return symbolSort.order === 'asc' ? (va < vb ? -1 : va > vb ? 1 : 0) : (va > vb ? -1 : va < vb ? 1 : 0);
    });
  }, [analytics?.topSymbols, symbolSort]);

  // Latency timeline points for chart
  const latencyPoints = useMemo(() => {
    if (analytics?.latencyData) return analytics.latencyData;
    // Build from latBuckets as fallback
    if (!analytics?.latBuckets || analytics.latBuckets.length === 0) return [];
    return analytics.latBuckets.map(b => ({ label: b.label, value: b.count }));
  }, [analytics]);

  function toggleSort(setter, key) {
    setter(prev => prev.key === key
      ? { key, order: prev.order === 'asc' ? 'desc' : 'asc' }
      : { key, order: 'desc' }
    );
  }

  const sm = analytics?.summary || {};

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <AnimatedPage className={s.page}>
      {/* Header */}
      <header className={s.header}>
        <div>
          <h1 className={s.title}>Execution Analytics</h1>
          {lastRefresh && (
            <span className={s.refreshLabel}>
              Last updated {lastRefresh.toLocaleTimeString()}
            </span>
          )}
        </div>
        <div className={s.headerControls}>
          <nav className={s.periodNav}>
            {PERIODS.map(p => (
              <Pill key={p.label} active={period.label === p.label} onClick={() => setPeriod(p)}>
                {p.label}
              </Pill>
            ))}
          </nav>
          <button className={s.refreshBtn} onClick={fetchData} title="Refresh now" type="button">
            &#x21BB;
          </button>
        </div>
      </header>

      {/* Tabs */}
      <nav className={s.tabBar}>
        {TABS.map(t => (
          <button
            key={t.key}
            className={`${s.tabBtn} ${tab === t.key ? s.tabBtnActive : ''}`}
            onClick={() => setTab(t.key)}
            type="button"
          >
            {t.label}
          </button>
        ))}
      </nav>

      {/* Loading */}
      {loading && !analytics && (
        <div className={s.loading}>Loading execution analytics...</div>
      )}

      {/* Error / Empty */}
      {error && !analytics && !loading && (
        <div className={s.emptyState}>
          <div className={s.emptyIcon}>&#x1F4CA;</div>
          <div className={s.emptyTitle}>No execution data available</div>
          <div className={s.emptyDesc}>
            Execution analytics will appear here once trades are executed through the platform.
            Make sure bots are running and orders have been placed.
          </div>
        </div>
      )}

      {/* Main Content */}
      {analytics && (
        <>
          {/* ═══ OVERVIEW TAB ═══ */}
          {tab === 'overview' && (
            <>
              {/* Summary Stats Row */}
              <section className={s.summaryRow}>
                <StatCard title="Total Orders" value={fmt(sm.totalOrders)} icon="&#x1F4CB;" color={RAW.blue} />
                <StatCard
                  title="Fill Rate"
                  value={sm.fillRate != null ? `${(sm.fillRate * 100).toFixed(1)}%` : '-'}
                  icon="&#x2705;"
                  color={qualityColor(sm.fillRate, { good: 0.95, mid: 0.8 })}
                  subtitle={`${fmt(sm.filledOrders)} filled`}
                />
                <StatCard
                  title="Avg Fill Time"
                  value={sm.avgFillTimeMs != null ? fmtMs(sm.avgFillTimeMs) : '-'}
                  icon="&#x23F1;"
                  color={qualityColorInverse(sm.avgFillTimeMs, { good: 100, mid: 250 })}
                />
                <StatCard
                  title="Avg Slippage"
                  value={sm.avgSlippageBps != null ? fmtBps(sm.avgSlippageBps) : '-'}
                  icon="&#x1F4C9;"
                  color={qualityColorInverse(sm.avgSlippageBps, { good: 3, mid: 10 })}
                />
                <StatCard
                  title="Rejected"
                  value={fmt(sm.rejectedOrders || 0)}
                  icon="&#x274C;"
                  color={sm.rejectedOrders > 0 ? RAW.red : RAW.green}
                />
                <StatCard
                  title="Pending"
                  value={fmt(sm.pendingOrders || 0)}
                  icon="&#x23F3;"
                  color={RAW.amber}
                />
              </section>

              {/* Fill Rate Gauge + Market Impact side by side */}
              <div className={s.splitRow}>
                <section className={s.splitPanel}>
                  <h2 className={s.sectionTitle}>Fill Rate</h2>
                  <FillRateGauge rate={sm.fillRate} total={sm.totalOrders} filled={sm.filledOrders} />
                </section>
                <section className={s.splitPanel}>
                  <h2 className={s.sectionTitle}>Market Impact Breakdown</h2>
                  <MarketImpactDonut segments={analytics.impactSegments} />
                </section>
              </div>

              {/* Order Flow Summary */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Order Flow Summary</h2>
                <div className={s.flowRow}>
                  <div className={s.flowCard}>
                    <span className={s.flowLabel}>Buy Orders</span>
                    <span className={s.flowValue} style={{ color: RAW.green }}>{fmt(sm.buys || 0)}</span>
                  </div>
                  <div className={s.flowCard}>
                    <span className={s.flowLabel}>Sell Orders</span>
                    <span className={s.flowValue} style={{ color: RAW.red }}>{fmt(sm.sells || 0)}</span>
                  </div>
                  {analytics.orderTypes?.map(ot => (
                    <div key={ot.type} className={s.flowCard}>
                      <span className={s.flowLabel}>{ot.type}</span>
                      <span className={s.flowValue}>{fmt(ot.count)}</span>
                      <span className={s.flowSub}>{ot.count > 0 && sm.totalOrders > 0 ? fmtPct(ot.count / sm.totalOrders) : ''}</span>
                    </div>
                  ))}
                </div>
              </section>

              {/* Execution Timing by Hour */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Execution Timing by Hour</h2>
                <div className={s.sectionSubtitle}>Order volume per hour of day (market hours highlighted)</div>
                <TimingByHour data={analytics.byHour || Array(24).fill(null)} />
              </section>

              {/* Algo Execution Status */}
              {analytics.algoStatus && (
                <section className={s.section}>
                  <h2 className={s.sectionTitle}>Algo Execution Status</h2>
                  <div className={s.algoGrid}>
                    {Object.entries(analytics.algoStatus).map(([name, info]) => {
                      const status = typeof info === 'object' ? (info.status || info.state || 'unknown') : info;
                      const isActive = (typeof status === 'string') && (status.toLowerCase() === 'active' || status.toLowerCase() === 'running');
                      return (
                        <div key={name} className={s.algoCard}>
                          <span className={s.algoDot} style={{ backgroundColor: isActive ? RAW.green : RAW.textSecondary }} />
                          <span className={s.algoName}>{name}</span>
                          <span className={s.algoState} style={{ color: isActive ? RAW.green : RAW.textSecondary }}>
                            {typeof status === 'string' ? status : JSON.stringify(status)}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </section>
              )}
            </>
          )}

          {/* ═══ SLIPPAGE TAB ═══ */}
          {tab === 'slippage' && (
            <>
              <section className={s.summaryRow}>
                <StatCard
                  title="Avg Slippage"
                  value={sm.avgSlippageBps != null ? fmtBps(sm.avgSlippageBps) : '-'}
                  color={qualityColorInverse(sm.avgSlippageBps, { good: 3, mid: 10 })}
                  icon="&#x1F4C9;"
                />
                <StatCard
                  title="Orders Analyzed"
                  value={fmt(sm.filledOrders || sm.totalOrders || 0)}
                  color={RAW.blue}
                  icon="&#x1F50D;"
                />
              </section>

              <section className={s.section}>
                <h2 className={s.sectionTitle}>Slippage Distribution</h2>
                <div className={s.sectionSubtitle}>
                  How slippage (in basis points) distributes across your filled orders
                </div>
                <SlippageHistogram buckets={analytics.slipBuckets} />
              </section>

              <section className={s.section}>
                <h2 className={s.sectionTitle}>Market Impact Breakdown</h2>
                <MarketImpactDonut segments={analytics.impactSegments} />
              </section>

              {/* Slippage by Symbol */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Slippage by Symbol</h2>
                <SortableTable
                  columns={[
                    { key: 'symbol', label: 'Symbol' },
                    { key: 'orders', label: 'Orders', numeric: true, format: v => fmt(v) },
                    { key: 'filled', label: 'Filled', numeric: true, format: v => fmt(v) },
                    { key: 'volume', label: 'Volume', numeric: true, format: v => fmt(v) },
                  ]}
                  data={sortedSymbols}
                  sortKey={symbolSort.key}
                  sortOrder={symbolSort.order}
                  onSort={k => toggleSort(setSymbolSort, k)}
                />
              </section>
            </>
          )}

          {/* ═══ LATENCY TAB ═══ */}
          {tab === 'latency' && (
            <>
              <section className={s.summaryRow}>
                <StatCard
                  title="Avg Latency"
                  value={sm.avgFillTimeMs != null ? fmtMs(sm.avgFillTimeMs) : '-'}
                  color={qualityColorInverse(sm.avgFillTimeMs, { good: 100, mid: 250 })}
                  icon="&#x23F1;"
                />
                <StatCard title="Fill Rate" value={sm.fillRate != null ? fmtPct(sm.fillRate) : '-'} color={qualityColor(sm.fillRate, { good: 0.95, mid: 0.8 })} icon="&#x2705;" />
              </section>

              {/* Latency Timeline */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Latency Timeline</h2>
                <div className={s.sectionSubtitle}>Fill latency over time (ms)</div>
                <LatencyTimeline points={latencyPoints} />
              </section>

              {/* Latency Distribution */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Latency Distribution</h2>
                <div className={s.barChart}>
                  {(analytics.latBuckets || []).map(b => {
                    const maxC = Math.max(...(analytics.latBuckets || []).map(x => x.count), 1);
                    const wPct = (b.count / maxC) * 100;
                    return (
                      <div key={b.label} className={s.barRow}>
                        <div className={s.barLabel}>{b.label}</div>
                        <div className={s.barTrack}>
                          <div className={s.barFill} style={{ width: `${wPct}%` }} />
                        </div>
                        <div className={s.barCount}>{b.count}</div>
                      </div>
                    );
                  })}
                </div>
              </section>

              {/* Timing by Hour */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Latency by Hour of Day</h2>
                <TimingByHour data={analytics.byHour || Array(24).fill(null)} />
              </section>
            </>
          )}

          {/* ═══ VENUES TAB ═══ */}
          {tab === 'venues' && (
            <>
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Venue / Broker Performance</h2>
                <div className={s.sectionSubtitle}>
                  Comparison of execution quality across venues
                </div>
                <SortableTable
                  columns={[
                    { key: 'venue', label: 'Venue' },
                    { key: 'orders', label: 'Orders', numeric: true, format: v => fmt(v) },
                    { key: 'filled', label: 'Filled', numeric: true, format: v => fmt(v) },
                    {
                      key: 'fillRate', label: 'Fill Rate', numeric: true,
                      format: v => fmtPct(v),
                      colorFn: v => qualityColor(v, { good: 0.95, mid: 0.8 }),
                    },
                    {
                      key: 'avgSlippageBps', label: 'Avg Slippage', numeric: true,
                      format: v => fmtBps(v),
                      colorFn: v => qualityColorInverse(v, { good: 3, mid: 10 }),
                    },
                    {
                      key: 'avgFillTimeMs', label: 'Avg Fill Time', numeric: true,
                      format: v => fmtMs(v),
                      colorFn: v => qualityColorInverse(v, { good: 100, mid: 250 }),
                    },
                  ]}
                  data={sortedVenues}
                  sortKey={venueSort.key}
                  sortOrder={venueSort.order}
                  onSort={k => toggleSort(setVenueSort, k)}
                />
              </section>

              {/* Venue volume breakdown as simple bars */}
              {sortedVenues.length > 0 && (
                <section className={s.section}>
                  <h2 className={s.sectionTitle}>Volume by Venue</h2>
                  <div className={s.barChart}>
                    {sortedVenues.map(v => {
                      const maxOrders = Math.max(...sortedVenues.map(x => x.orders), 1);
                      const wPct = (v.orders / maxOrders) * 100;
                      return (
                        <div key={v.venue} className={s.barRow}>
                          <div className={s.barLabel} style={{ width: 120 }}>{v.venue}</div>
                          <div className={s.barTrack}>
                            <div className={s.barFill} style={{ width: `${wPct}%` }} />
                          </div>
                          <div className={s.barCount}>{v.orders}</div>
                        </div>
                      );
                    })}
                  </div>
                </section>
              )}
            </>
          )}

          {/* ═══ ORDER FLOW TAB ═══ */}
          {tab === 'orderflow' && (
            <>
              {/* Order type breakdown */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Order Type Breakdown</h2>
                <div className={s.orderTypeRow}>
                  {(analytics.orderTypes || []).map(ot => {
                    const fr = ot.count > 0 ? ot.filled / ot.count : 0;
                    return (
                      <div key={ot.type} className={s.orderTypeCard}>
                        <div className={s.orderTypeLabel}>{ot.type}</div>
                        <div className={s.orderTypeValue}>{fmt(ot.count)}</div>
                        <div className={s.orderTypeSub}>
                          {fmtPct(fr)} fill rate
                        </div>
                      </div>
                    );
                  })}
                </div>
              </section>

              {/* Buy/Sell ratio */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Buy / Sell Ratio</h2>
                <div className={s.ratioBar}>
                  {(sm.buys || 0) + (sm.sells || 0) > 0 ? (
                    <>
                      <div
                        className={s.ratioFillBuy}
                        style={{ width: `${((sm.buys || 0) / ((sm.buys || 0) + (sm.sells || 0))) * 100}%` }}
                      >
                        BUY {fmt(sm.buys || 0)}
                      </div>
                      <div
                        className={s.ratioFillSell}
                        style={{ width: `${((sm.sells || 0) / ((sm.buys || 0) + (sm.sells || 0))) * 100}%` }}
                      >
                        SELL {fmt(sm.sells || 0)}
                      </div>
                    </>
                  ) : (
                    <div className={s.noData}>No order flow data</div>
                  )}
                </div>
              </section>

              {/* Top Symbols */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Top Symbols by Volume</h2>
                <SortableTable
                  columns={[
                    { key: 'symbol', label: 'Symbol' },
                    { key: 'orders', label: 'Orders', numeric: true, format: v => fmt(v) },
                    { key: 'filled', label: 'Filled', numeric: true, format: v => fmt(v) },
                    { key: 'volume', label: 'Volume', numeric: true, format: v => fmt(v) },
                  ]}
                  data={sortedSymbols}
                  sortKey={symbolSort.key}
                  sortOrder={symbolSort.order}
                  onSort={k => toggleSort(setSymbolSort, k)}
                />
              </section>

              {/* Recent Fills */}
              <section className={s.section}>
                <h2 className={s.sectionTitle}>Recent Fills</h2>
                <SortableTable
                  columns={[
                    { key: 'symbol', label: 'Symbol' },
                    { key: 'side', label: 'Side', format: (v) => v, colorFn: v => (v || '').toUpperCase() === 'BUY' ? RAW.green : RAW.red },
                    { key: 'qty', label: 'Qty', numeric: true, format: v => fmt(v) },
                    { key: 'price', label: 'Price', numeric: true, format: v => fmtUsd(v) },
                    { key: 'orderType', label: 'Type' },
                    { key: 'status', label: 'Status', colorFn: v => {
                      const st = (v || '').toLowerCase();
                      if (st === 'filled' || st === 'complete') return RAW.green;
                      if (st === 'rejected' || st === 'cancelled' || st === 'error') return RAW.red;
                      if (st === 'pending' || st === 'submitted') return RAW.amber;
                      return RAW.textSecondary;
                    }},
                    { key: 'slippageBps', label: 'Slippage', numeric: true, format: v => fmtBps(v), colorFn: v => qualityColorInverse(v, { good: 3, mid: 10 }) },
                    { key: 'bot', label: 'Bot' },
                    { key: 'venue', label: 'Venue' },
                    { key: 'timestamp', label: 'Time', format: v => fmtTime(v) },
                  ]}
                  data={sortedFills}
                  sortKey={fillsSort.key}
                  sortOrder={fillsSort.order}
                  onSort={k => toggleSort(setFillsSort, k)}
                />
              </section>
            </>
          )}
        </>
      )}
    </AnimatedPage>
  );
}
